// Plant.java - Model class for Plant\n\npackage com.oceanoseal.greengarden;\n\npublic class Plant {\n    private String name;\n    private String type;\n    private int age;\n\n    public Plant(String name, String type, int age) {\n        this.name = name;\n        this.type = type;\n        this.age = age;\n    }\n\n    public String getName() {\n        return name;\n    }\n\n    public void setName(String name) {\n        this.name = name;\n    }\n\n    public String getType() {\n        return type;\n    }\n\n    public void setType(String type) {\n        this.type = type;\n    }\n\n    public int getAge() {\n        return age;\n    }\n\n    public void setAge(int age) {\n        this.age = age;\n    }\n}\n